import * as api from '../api';

// Action Creators
const getPosts = () => async (dispatch) => {
    try {
        const {data} = await api.fetchPosts(); // fetchPosts return a response which always has a data object -- destructuring expression
        dispatch({type: 'FETCH ALL', payload: data});
    } catch (error) {

    }

}
